def test_create_patient_all_mandatory_fields_returns_201(fhir_client, clinician_token):
    payload = {
        "resourceType": "Patient",
        "name": [{"family": "Doe", "given": ["Jane"]}],
        "gender": "female",
        "birthDate": "1990-06-15"
    }
    resp = fhir_client.post(
        "/Patient",
        json=payload,
        headers={"Authorization": f"Bearer {clinician_token}"}
    )
    assert resp.status_code == 201, f"Expected 201, got {resp.status_code}: {resp.text}"
    assert "Location" in resp.headers, "Location header missing"
    body = resp.json()
    assert "id" in body, "Response body must contain 'id'"
    # Teardown: remove created resource to keep environment clean
    resource_id = body["id"]
    fhir_client.delete(
        f"/Patient/{resource_id}",
        headers={"Authorization": f"Bearer {clinician_token}"}
    )

def test_create_patient_family_name_at_max_length_boundary(fhir_client, clinician_token):
    MAX_LEN = 64
    boundary_name = "A" * MAX_LEN
    assert len(boundary_name) == MAX_LEN
    payload = {
        "resourceType": "Patient",
        "name": [{"family": boundary_name, "given": ["Test"]}],
        "gender": "unknown",
        "birthDate": "2000-01-01"
    }
    resp = fhir_client.post(
        "/Patient",
        json=payload,
        headers={"Authorization": f"Bearer {clinician_token}"}
    )
    assert resp.status_code == 201, \
        f"Expected 201 for max-length name ({MAX_LEN} chars), got {resp.status_code}: {resp.text}"
    body = resp.json()
    assert "id" in body
    fhir_client.delete(
        f"/Patient/{body['id']}",
        headers={"Authorization": f"Bearer {clinician_token}"}
    )

def test_create_patient_after_consent_revocation_is_rejected(
    fhir_client, clinician_token, revoke_consent, wait_for_consent_propagation
):
    subject_ref = "urn:test:consent-subject-001"
    revoke_consent(subject_ref)          # <revoke_consent> fixture
    wait_for_consent_propagation()       # <wait_for_consent_propagation> fixture
    payload = {
        "resourceType": "Patient",
        "name": [{"family": "Revoked", "given": ["Consent"]}],
        "gender": "male",
        "birthDate": "1985-03-22",
        "extension": [{
            "url": "urn:fhir-lite:consent-subject",
            "valueString": subject_ref
        }]
    }
    resp = fhir_client.post(
        "/Patient",
        json=payload,
        headers={"Authorization": f"Bearer {clinician_token}"}
    )
    assert resp.status_code in (403, 422), \
        f"Expected 403 or 422 post-revocation, got {resp.status_code}: {resp.text}"
    body_text = str(resp.json()).lower()
    assert "consent" in body_text or "forbidden" in body_text or "unauthorized" in body_text, \
        f"Response must reference consent failure: {resp.json()}"

import pytest

def test_create_patient_decision_table_gender_values(fhir_client, clinician_token):
    base = {
        "resourceType": "Patient",
        "name": [{"family": "DTTest", "given": ["Gender"]}],
        "birthDate": "1975-11-30"
    }
    # Decision: invalid gender -> reject
    bad_payload = {**base, "gender": "nonbinary"}
    bad_resp = fhir_client.post(
        "/Patient",
        json=bad_payload,
        headers={"Authorization": f"Bearer {clinician_token}"}
    )
    assert bad_resp.status_code == 422, \
        f"Expected 422 for invalid gender, got {bad_resp.status_code}: {bad_resp.text}"
    # Decision: valid gender -> accept
    good_payload = {**base, "gender": "other"}
    good_resp = fhir_client.post(
        "/Patient",
        json=good_payload,
        headers={"Authorization": f"Bearer {clinician_token}"}
    )
    assert good_resp.status_code == 201, \
        f"Expected 201 for valid gender 'other', got {good_resp.status_code}: {good_resp.text}"
    body = good_resp.json()
    fhir_client.delete(
        f"/Patient/{body['id']}",
        headers={"Authorization": f"Bearer {clinician_token}"}
    )
